_ohm":{"value":200,"unit_orig":"Ω","reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Impedance: ≤ 200 ohms"},"note":"Stated as ≤ 200 ohms."},"phantom":{"value":"required","unit_orig":null,"reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Powering: 48 V phantom power to IEC 61938"}},"pad_db":{"value":[6,12,18],"unit_orig":"dB","reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Pre-attenuation pads: -6 dB, 112 dB, -18 dB (selectable)"},"note":"OCR glitch: '112 dB' should read '-12 dB'. Corroborated by the Max SPL line '(0/-6/-12/-18 dB pre-attenuation)'. Actual pads: -6/-12/-18 dB."},"hpfBuiltin":{"value":"Switchable bass-cut: 12 dB/octave at 40 Hz and 80 Hz; 6 dB/octave at 160 Hz","unit_orig":null,"reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Bass cut filter slopes: 12 dB/octave at 40 Hz and 80 Hz; 6 dB/octave at 160 Hz"}},"dims":{"value":"50 x 38 x 160 (W x D x H)","unit_orig":"mm","reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Dimensions: 50 x 38 x 160 mm / 2 x 1.5 x 6.3 in."}},"weight_g":{"value":300,"unit_orig":"g","reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Net weight: 300 g / 10.6 oz."}},"connector":{"value":"XLR3","unit_orig":null,"reliability":"official","source":{"doc":"AKG_C414XLS_C414XLII_CutSheet.pdf","page":2,"quote":"Connector: 3-pin XLR (pin 2 hot)"},"note":"Datasheet states '3-pin XLR (pin 2 hot)'; gender not specified (mic output is male)."}}$eq$::jsonb)
