note":"Passive ribbon — phantom power must NOT be applied (rule: passive ribbon→ribbon_danger)."},"pad_db":{"value":null,"unit_orig":null,"reliability":"official","source":null,"note":"No pad switch on R-121 (fully passive)."},"hpfBuiltin":{"value":false,"unit_orig":null,"reliability":"derived","source":null,"note":"No filter/HPF (fully passive ribbon). · derivato (nessuna citazione diretta; es. phantom dal principle)"},"dims":{"value":"156 x Ø25 (length x diameter)","unit_orig":"mm","reliability":"official","source":{"doc":"Royer_R-121_CutSheet.pdf","page":2,"quote":"156mm L X 25mm W (6.25\" L X 1\" W)"}},"weight_g":{"value":244,"unit_orig":"g","reliability":"official","source":{"doc":"Royer_R-121_CutSheet.pdf","page":2,"quote":"Weight 244g (8.6 oz)"}},"connector":{"value":"XLR3M","unit_orig":null,"reliability":"official","source":{"doc":"Royer_R-121_CutSheet.pdf","page":2,"quote":"Output Connector Male XLR 3-pin (Pin 2 Hot)"}}}$eq$::jsonb)
