values ('radial-j48', 'Radial', 'J48', 'di', 'current', 'radial-j48-smartsheet', $eq${"id":"radial-j48","brand":"Radial","model":"J48","category":"di","active":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"J48 active direct box ... the world's finest phantom-powered active DI"}},"channels":{"value":1,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"INPUT connects from instrument, the THRU to the amplifier ... XLR OUT"},"note":"Mono (single-channel) DI: one instrument input, one thru, one XLR output. Not stated numerically; inferred from single-channel signal path (Merge sums a stereo source to the mono output)."},"phantom":{"value":"required","unit_orig":null,"reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"No batteries required, works with phantom-power"},"note":"Active DI powered exclusively by 48 V phantom (5 mA)."},"pad_db":{"value":[15],"unit_orig":"dB","reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"-15dB PAD allows super-hot inputs"}},"groundLift":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"GROUND-LIFT disconnects the internal ground path between the input and the output"}},"impedance_input_ohm":{"value":null,"unit_orig":null,"reliability":"official","source":null,"note":"Described as 'High input impedance' but no numeric value given. (600 Ω figure on the sheet is the balanced XLR OUTPUT impedance, not input.)"},"maxLevel_dbu":{"value":null,"unit_orig":null,"reliability":"official","source":null,"note":"No max input/output level in dBu on the smart sheet (internal rail 9 V)."},"transformer":{"value":false,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"unique digital switch-mode power supply that steps up the internal rail voltage to an amazing 9-Volts"},"note":"Active/transformerless DI; no transformer mentioned — uses a digital switch-mode PSU."},"connectors":{"value":"in: 1/4\" jack (instrument); thru: 1/4\" jack (to amp); out: XLR male, 600 Ω balanced mic-level","unit_orig":null,"reliability":"official","source":{"doc":"Radial_J48_SmartSheet.pdf","page":1,"quote":"INPUT connects from instrument, the THRU to the amplifier ... XLR OUT 600 Ohm balanced, mic-level output"},"note":"Input/Thru described as 'jacks' (1/4\" TS standard); output is XLR."}}$eq$::jsonb)
