values ('radial-jdi', 'Radial', 'JDI', 'di', 'current', 'radial-jdi-smartsheet', $eq${"id":"radial-jdi","brand":"Radial","model":"JDI","category":"di","active":{"value":false,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"JDI passive direct box ... the world's finest passive direct box"}},"channels":{"value":1,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"INPUT connects to the instrument, THRU feeds the amplifier ... XLR balanced, mic-level output"},"note":"Mono (single-channel) passive DI: one input, one thru, one XLR output. Not stated numerically; inferred from single-channel signal path."},"phantom":{"value":"no","unit_orig":null,"reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"Passive operation, no power required"}},"pad_db":{"value":[15],"unit_orig":"dB","reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"-15dB PAD reduces input sensitivity for active high-output instruments"},"note":"Also an optional -30 dB pad in the Parallel Speaker interface mode (with band-pass filter)."},"groundLift":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"GROUND LIFT disconnects pin-1 at the XLR output to help eliminate hum and buzz from ground loops"}},"impedance_input_ohm":{"value":null,"unit_orig":null,"reliability":"official","source":null,"note":"Input impedance not given numerically on this smart sheet (uses Jensen JT-DB-EPC transformer)."},"maxLevel_dbu":{"value":null,"unit_orig":null,"reliability":"official","source":null,"note":"No max level in dBu on the smart sheet."},"transformer":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"The JDI employs a Jensen JT-DB-EPC audio transformer"}},"connectors":{"value":"in: 1/4\" jack (instrument); thru: 1/4\" jack (to amp); out: XLR balanced mic-level","unit_orig":null,"reliability":"official","source":{"doc":"Radial_JDI_SmartSheet.pdf","page":1,"quote":"INPUT connects to the instrument, THRU feeds the amplifier ... XLR balanced, mic-level output"},"note":"Input/Thru described as 'jacks' (1/4\" TS standard); output is XLR."}}$eq$::jsonb)
