values ('countryman-type85', 'Countryman', 'Type 85', 'di', 'current', 'countryman-type85-datasheet', $eq${"id":"countryman-type85","brand":"Countryman","model":"Type 85","category":"di","active":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":1,"quote":"TYPE 85 ACTIVE DIRECT BOX"}},"channels":{"value":1,"unit_orig":null,"reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":1,"quote":"connects any high-impedance instrument pickup ... to a balanced microphone (XLR type) input"},"note":"Mono (single-channel) DI: one INST input, one parallel AMP thru, one XLR MIC output. Not stated numerically; inferred from single-channel signal path."},"phantom":{"value":"optional_battery","unit_orig":null,"reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":1,"quote":"Power Requirements: 9 V battery or .4 mA @ 48 V Phantom"},"note":"Runs on internal 9 V battery OR 48 V phantom (auto-switches to phantom; works down to 24 V phantom, p2)."},"pad_db":{"value":null,"unit_orig":null,"reliability":"official","source":null,"note":"No dedicated pad switch. Voltage gain is -10 dB in Pickup mode and -46 dB in Speaker mode (Pickup/Speaker mode switch, not a pad). Datasheet: 'doesn't have roll off switches or effects'."},"groundLift":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":1,"quote":"the Type 85 can always isolate ground, even when running on Phantom power, to help eliminate hum and buzz"},"note":"Rear GND/OPEN ground switch shown in the hook-up diagrams (p2)."},"impedance_input_ohm":{"value":10000000,"unit_orig":"MΩ","reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":1,"quote":"Input Resistance: 10 MΩ in Pickup mode"},"note":"10 MΩ (Pickup mode); converted to 10,000,000 Ω."},"maxLevel_dbu":{"value":null,"unit_orig":"V P-P","reliability":"official","source":null,"note":"Not given in dBu. Datasheet states Maximum Input Level: 5 V P-P (Pickup mode), 300 V P-P (Speaker mode) on p1."},"transformer":{"value":false,"unit_orig":null,"reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":1,"quote":"hand-selected high-quality discrete components woven into a single-ended class A circuit"},"note":"Active class-A, transformerless; ground isolation done electronically. No transformer mentioned."},"connectors":{"value":"in: 1/4\" INST jack; thru: 1/4\" AMP jack (parallel to INST); out: XLR MIC OUTPUT","unit_orig":null,"reliability":"official","source":{"doc":"Countryman_Type85_Datasheet.pdf","page":2,"quote":"INST / AMP jacks (front); MIC OUTPUT (back)"},"note":"AMP jack is wired in parallel with INST; MIC OUTPUT is XLR (balanced mic-level)."}}$eq$::jsonb)
