values ('aviom-a360', 'Aviom', 'A360 Personal Mixer', 'personal_mixer', 'current', 'aviom-a360-userguide', $eq${"id":"aviom-a360","brand":"Aviom","model":"A360 Personal Mixer","category":"personal_mixer","channels":{"value":16,"unit_orig":"channels","reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":11,"quote":"16 mono or stereo standard mix channels"}},"stereoPairs":{"value":null,"unit_orig":null,"reliability":"official","source":null},"protocol":{"value":"A-Net (Pro16/Pro16e)","unit_orig":null,"reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"A-Net I/O  1 A-Net In, Neutrik EtherCon RJ45 connector; Supports Pro16 and Pro16e"}},"hubConn":{"value":"A-Net In (Neutrik EtherCon RJ45); connects to an A-Net Distributor (e.g. D800) or analog input module / console card","unit_orig":null,"reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"1 A-Net In, Neutrik EtherCon RJ45 connector; Supports Pro16 and Pro16e"}},"daisyChain":{"value":false,"unit_orig":null,"reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":66,"quote":"the A360 has only an A-Net In port and must be the last device in a daisy chain. Adding more than one A360 Personal Mixer to such a system requires the addition of an A-Net Distributor."}},"powerOverData":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"A-Net Pro16e Protocol ... Supports Power Over A-Net"}},"localPSU":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"Optional Power Supply  External, DC, universal switching type; Input Voltage 100-240 volts, 50/60Hz; Output Voltage 24 VDC, 0.5 amp"}},"maxUnits":{"value":null,"unit_orig":null,"reliability":"official","source":null},"ports_in":{"value":1,"unit_orig":"port","reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"A-Net I/O  1 A-Net In, Neutrik EtherCon RJ45 connector"}},"ports_thru":{"value":0,"unit_orig":"port","reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":66,"quote":"the A360 has only an A-Net In port and must be the last device in a daisy chain"}},"connectors":{"value":"1/4\" TRS stereo out (headphone/line); 1/8\" TRS stereo out; XLR balanced mono out; 1 A-Net In (Neutrik EtherCon RJ45); USB storage; 24VDC power jack","unit_orig":null,"reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"Audio Outputs 1/4\" TRS stereo ...; 1/8\" TRS stereo ...; XLR balanced mono ...; A-Net I/O 1 A-Net In, Neutrik EtherCon RJ45"}},"dims":{"value":"279.4 x 175.26 x 46.61","unit_orig":"mm","reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"Dimensions 11\" (279.4 mm) wide x 6.9\" (175.26 mm) deep; 1.835\" (46.61 mm) high"}},"weight_kg":{"value":1.54,"unit_orig":"kg","reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"Weight 3.4 lb. (1.54 kg)"}},"power":{"value":"24VDC 0.5A (external DC PSU PS-120) or Power Over A-Net via Cat-5e","unit_orig":"VDC/A","reliability":"official","source":{"doc":"Aviom_A360_UserGuide.pdf","page":81,"quote":"Input Voltage 100-240 volts, 50/60Hz; Output Voltage 24 VDC, 0.5 amp; Supports Power Over A-Net"}},"_notes":["dims order = W x D x H (per source order). Dimension-drawing depth reads 181.712 mm incl. connectors vs 175.26 mm chassis in spec table; used spec table value.","stereoPairs: 16 channels are individually mono OR stereo-linked per pair (link set at the input module) but the manual gives no fixed pair count -> null.","daisyChain=false because the A360 has only an A-Net In (no thru/A-Net Out): it can only sit as the LAST unit in a chain, it cannot pass A-Net onward.","maxUnits null: 'An unlimited number of A-Net devices can be used in a system'; per-distributor fan-out is 8 (via a D800). No fixed per-mixer max.","localPSU: PS-120 external DC PSU is OPTIONAL for star topology but REQUIRED when the A360 is placed in a daisy chain."]}$eq$::jsonb)
