values ('aviom-d800', 'Aviom', 'D800 A-Net Distributor', 'hub', 'current', 'aviom-d800-distributor-userguide', $eq${"id":"aviom-d800","brand":"Aviom","model":"D800 A-Net Distributor","category":"hub","channels":{"value":64,"unit_orig":"channels","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Pro16e A-Net Support  Transmits up to 64 channels of digital audio to A360 & A320 Personal Mixers"}},"stereoPairs":{"value":null,"unit_orig":null,"reliability":"official","source":null},"protocol":{"value":"A-Net (Pro16/Pro16e)","unit_orig":null,"reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"A-Net In or A-Net Bridge In  Accepts Pro16 or Pro16e A-Net; One locking RJ45 connector"}},"hubConn":{"value":"A-Net In / A-Net Bridge In (1x locking RJ45); receives from an analog input module or digital console card; A-Net Out (Pro16e) for chaining more distributors","unit_orig":null,"reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"A-Net In or A-Net Bridge In  Accepts Pro16 or Pro16e A-Net; One locking RJ45 connector"}},"daisyChain":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"A-Net Out (rear panel)  Pro16e A-Net; One locking RJ45 connector, unpowered"}},"powerOverData":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Output Voltage for Personal Mixers  24VDC, 0.5 amp  Transmitted over the Cat-5e cable"}},"localPSU":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Power Supply  Internal, universal switching type, IEC connector"}},"maxUnits":{"value":8,"unit_orig":"personal mixers","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"A-Net to/from Personal Mixers (front panel)  Eight locking RJ45 connectors, powered"}},"ports_in":{"value":1,"unit_orig":"port","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"A-Net In or A-Net Bridge In ... One locking RJ45 connector"}},"ports_out":{"value":8,"unit_orig":"ports","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Eight locking RJ45 connectors, powered ... accommodates A320, A-16II (I) and the bidirectional A640 and A360 Personal Mixer (II)"}},"ports_thru":{"value":1,"unit_orig":"port","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"A-Net Out (rear panel)  Pro16e A-Net; One locking RJ45 connector, unpowered"}},"connectors":{"value":"8x front powered RJ45 (to personal mixers, I/II switch); 1x A-Net In / A-Net Bridge In (RJ45); 1x A-Net Out (RJ45); 1x A-Net Mixes Out (RJ45, Network Mix Back, up to 16 ch); 1x Ethernet (RJ45); USB (firmware); IEC mains","unit_orig":null,"reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Eight locking RJ45 connectors, powered; A-Net In or A-Net Bridge In; A-Net Out; A-Net Mixes Out ... Ethernet One RJ45 connector; USB"}},"dims":{"value":"482.6 x 362 x 88.9","unit_orig":"mm","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Dimensions  19\" (482.6 mm) wide x 14.25\" (362 mm) deep; 2U, 3.5\" (88.9 mm) high"}},"weight_kg":{"value":5.44,"unit_orig":"kg","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Weight  12.0 lbs (5.44 kg)"}},"power":{"value":"100-240VAC 50-60Hz 300W (internal PSU); outputs 24VDC 0.5A to mixers over Cat-5e","unit_orig":"VAC/W","reliability":"official","source":{"doc":"Aviom_D800_Distributor_UserGuide.pdf","page":51,"quote":"Input Voltage  100-240VAC, 50-60Hz, 300W  Fuse - 250VAC~ T4AL"}},"_notes":["dims order = W x D x H, 2U rack. This is the HUB/distributor (category 'hub').","channels=64 is Pro16e capacity to A360/A320; original Pro16 to A-16II/A-16R carries 16 channels ('Transmits 16 channels of digital audio to A-16II and A-16R').","Added non-schema field ports_out=8 (the 8 powered outputs to personal mixers) because it is the D800's defining spec; ports_thru=1 is the rear A-Net Out for chaining distributors.","stereoPairs null for standard D800; the D800-Dante variant adds DIP-switch stereo link up to 32 pairs (separate model, not this base unit).","300W is the internal PSU input rating (it powers up to 8 mixers over Cat-5e)."]}$eq$::jsonb)
