values ('behringer-p16m', 'Behringer', 'Powerplay P16-M', 'personal_mixer', 'current', 'behringer-powerplay-p16-m-manual', $eq${"id":"behringer-p16m","brand":"Behringer","model":"Powerplay P16-M","category":"personal_mixer","channels":{"value":16,"unit_orig":"channels","reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":1,"quote":"16-channel digital stereo mixer to create your personal monitor mix"}},"stereoPairs":{"value":null,"unit_orig":null,"reliability":"official","source":null},"protocol":{"value":"ULTRANET","unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":1,"quote":"ULTRANET connector to daisy-chain up to forty-eight P16-M mixers for large systems (in conjunction with P16-D)"}},"hubConn":{"value":"CAT5e from P16-I audio interface or P16-D ULTRANET distributor","unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":1,"quote":"Standard CAT5e connection delivers power and 16 signals to each Personal Mixers"}},"daisyChain":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":1,"quote":"ULTRANET connector to daisy-chain up to forty-eight P16-M mixers for large systems (in conjunction with P16-D)"}},"powerOverData":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":1,"quote":"Standard CAT5e connection delivers power and 16 signals to each Personal Mixers"}},"localPSU":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":2,"quote":"Powered via external power supply (included) or P16-I / P16-D"}},"maxUnits":{"value":48,"unit_orig":"mixers","reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":1,"quote":"daisy-chain up to forty-eight P16-M mixers for large systems (in conjunction with P16-D)"}},"ports_in":{"value":1,"unit_orig":"port","reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":3,"quote":"ULTRANET IN/THRU connectors for daisy-chaining additional devices"}},"ports_thru":{"value":1,"unit_orig":"port","reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":3,"quote":"ULTRANET IN/THRU connectors for daisy-chaining additional devices"}},"connectors":{"value":"ULTRANET IN/THRU (RJ45); PHONES jack; LINE OUT 1/4\" jacks (mono/stereo); MIDI IN (5-pin DIN); DC power input","unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":4,"quote":"ULTRANET IN/THRU connectors ...; PHONES jack accepts standard headphones or wired in-ear monitors; LINE OUT 1/4\" jacks ...; MIDI IN port"}},"dims":{"value":"238 × 127 × 55 mm","unit_orig":"mm","value_norm":null,"unit_norm":"mm","reliability":"official","source":{"doc":"Behringer_P16-M_SpecSheet.pdf","page":2,"quote":"appr. 238 x 127 x 55 mm"},"extractedAt":"2026-07-16"},"weight_kg":{"value":0.8,"unit_orig":"kg","value_norm":0.8,"unit_norm":"kg","reliability":"official","source":{"doc":"Behringer_P16-M_SpecSheet.pdf","page":2,"quote":"appr. 1.8 lbs / 0.8 kg"},"extractedAt":"2026-07-16"},"power":{"value":"External DC PSU (included) or bus-power over CAT5e from P16-I / P16-D","unit_orig":null,"reliability":"official","source":{"doc":"Behringer_Powerplay_P16-M_Manual.pdf","page":2,"quote":"Powered via external power supply (included) or P16-I / P16-D"}},"_notes":["Source PDF is a 5-page marketing brochure/datasheet, NOT a full manual: it has NO specifications table, so dims, weight and exact power V/W are absent (null).","48 mixers max requires P16-D distributors (up to six P16-D combined drive 48 P16-M).","stereoPairs null: brochure mentions selecting a 'stereo pair' but gives no pair count.","Ultra-low system latency < 1 ms; MIDI IN allows remote control of all channels (e.g. BCF2000/BCR2000)."]}$eq$::jsonb)
