insert into equip_product (id, brand, model, category, commercial_status, primary_source_doc, data)
values ('hear-hb-octo', 'Hear Technologies', 'Hear Back OCTO (Mixer)', 'personal_mixer', 'current', 'heartech-hearback-octo-userguide-2019', $eq${"id":"hear-hb-octo","brand":"Hear Technologies","model":"Hear Back OCTO (Mixer)","category":"personal_mixer","channels":{"value":8,"unit_orig":"channels","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"Local control of up to ten channels of audio (eight inputs plus a stereo AUX input)"}},"stereoPairs":{"value":4,"unit_orig":"pairs","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":9,"quote":"Link Indicators (Channels 1/2, 3/4, 5/6, 7/8)"}},"protocol":{"value":"HearBus","unit_orig":null,"reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"The Hub receives any of three input signal sources and converts them to HearBus digital audio plus power. The Mixers are connected to the Hub using CAT5e cable."}},"hubConn":{"value":"CAT5e home-run to a Hear Back OCTO Hub; one Hub feeds up to 8 Mixers","unit_orig":null,"reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"A single Hub will supply digital audio and power to a maximum of eight Mixers. ... Each of the eight Hub outputs must make a “home run” to a Mixer, with a maximum distance of 200 feet."}},"daisyChain":{"value":false,"unit_orig":null,"reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"Each of the eight Hub outputs must make a “home run” to a Mixer ... DO NOT “Y” these connections"}},"powerOverData":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"The Hub has Mixer outputs which each deliver digital audio, ground and +/- 17.5VDC ... Standard CAT5e cable for power and signal connection to Mixers"}},"localPSU":{"value":false,"unit_orig":null,"reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"Standard CAT5e cable for power and signal connection to Mixers"}},"maxUnits":{"value":8,"unit_orig":"mixers","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"A single Hub will supply digital audio and power to a maximum of eight Mixers."}},"ports_in":{"value":1,"unit_orig":"port","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":9,"quote":"RJ45 Connection"}},"ports_thru":{"value":0,"unit_orig":"port","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"Each of the eight Hub outputs must make a “home run” to a Mixer ... DO NOT “Y” these connections"}},"connectors":{"value":"1x RJ45 (CAT5e from Hub); 1/8\" TRS + 1/4\" TRS headphone out; 2x 1/4\" TRS balanced line out (Left/Mono, Right); 1/8\" TRS stereo AUX in","unit_orig":null,"reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":13,"quote":"Mixer Headphone Out: 1x TRS 1/8” and 1x 1/4” unbalanced stereo; Mixer Line Out: 2x TRS 1/4” balanced (left/mono or stereo); Mixer Aux Input: TRS 1/8” unbalanced stereo"}},"dims":{"value":"236.2 x 64.0 x 129.5","unit_orig":"mm","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":13,"quote":"Physical, Mixer  Size: 5.1” H x 9.3” W x 2.519” D (12.95 cm H x 23.62 cm W x 6.40 cm D)"}},"weight_kg":{"value":0.45,"unit_orig":"kg","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":13,"quote":"Unit Weight: 15.8 oz. (0.45 kg)"}},"power":{"value":"Bus-powered over CAT5e, +/-17.5VDC supplied by the Hub","unit_orig":"VDC","reliability":"official","source":{"doc":"HearTech_HearBack_OCTO_UserGuide_2019.pdf","page":7,"quote":"The Hub has Mixer outputs which each deliver digital audio, ground and +/- 17.5VDC"}},"_notes":["This record represents the OCTO personal MIXER (category personal_mixer). The user guide also covers the OCTO HUB (separate device).","dims order = W x D x H (source lists H x W x D; reordered). Values: W 236.2, D 64.0, H 129.5 mm.","channels=8 network inputs; a stereo AUX in (1/8\") adds 2 more locally controllable channels -> 'up to ten channels'.","daisyChain=false at the MIXER level: each mixer is a home-run to the Hub (no thru, Y-connections forbidden). The HUBS themselves daisy-chain via HearBus In/Out up to 500 ft for 'virtually unlimited system size'.","localPSU=false: mixer is bus-powered from the Hub. The HUB has an internal universal PSU rated 100-240VAC 125W 50/60Hz (page 13).","Headphone amp: up to ~2 W into 50 ohm; system latency < 1.5 ms; Hub is 1RU, 19\" (48.26 cm) wide, 1.79 kg."]}$eq$::jsonb)
on conflict (id) do update set data=excluded.data, updated_at=now();
insert into equip_product (id, brand, model, category, commercial_status, primary_source_doc, data)
values ('digico-sd9', 'DiGiCo', 'SD9', 'console', 'current', 'digico-sd9-datasheet', $eq${"id":"digico-sd9","brand":"DiGiCo","model":"SD9","category":"console","physicalInputs":{"value":8,"unit_orig":"XLR mic/line","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"8 x XLR Mic/Line Inputs"}},"micPreamps":{"value":8,"unit_orig":"preamps","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"8 x XLR Mic/Line Inputs"}},"processingChannels":{"value":96,"unit_orig":"channels","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"96 Input Channels (Mono)"}},"mixBuses":{"value":48,"unit_orig":"busses","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"48 Aux/Sub-Group busses with full processing"}},"auxBuses":{"value":null,"unit_orig":null,"reliability":"official","source":null},"matrices":{"value":"12x8","unit_orig":"in x out","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"12 Input x 8 Output Full Processing Matrix"}},"groups":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dca":{"value":12,"unit_orig":"control groups","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"12 Control Groups (CGs)  ... 12 VCA style or mute group style Control Group channels"}},"directOut":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"Channel Direct Outputs"}},"insert":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"1 Insert Point per Channel"}},"sampleRate_khz":{"value":"48/96","unit_orig":"kHz","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":3,"quote":"Sample Rate: 48kHz or 96kHz"}},"expansionProtocols":{"value":"MADI (1x BNC I/O + 2x RJ45 EtherCon for D-Rack); AES/EBU; Word Clock; optional Waves SoundGrid; optional Optocore (HMA/OpticalCon/ST)","unit_orig":null,"reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"1 x MADI BNC I/O; 2 x MADI RJ45 Ethercon I/O (for D-Rack); ... 1 x MultiMode Optocore Interface (Optional); Waves SoundGrid Interface"}},"maxStageboxes":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dims":{"value":"878 x 785 x 262","unit_orig":"mm","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":4,"quote":"Dimensions: 878mm (w) x 785mm (d) x 262mm (h)"}},"weight_kg":{"value":36,"unit_orig":"kg","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":4,"quote":"Weight: 36kg (105kg with optional flightcase)"}},"powerConsumption_W":{"value":208,"unit_orig":"W","reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":4,"quote":"Power Requirements: 90-264 VAC, 47-63Hz Auto Sensing. 208 watts, 232VA"}},"connectors":{"value":"8x XLR Mic/Line in; 8x XLR Line out; 2x XLR AES/EBU in (4 ch); 2x XLR AES/EBU out (4 ch); 1x MADI BNC I/O; 2x MADI RJ45 EtherCon (D-Rack); Word Clock BNC I/O; MIDI In/Thru/Out; 2x GPI; 2x GPO; Ethernet; 2x USB 2.0; VGA (DB-15)","unit_orig":null,"reliability":"official","source":{"doc":"DiGiCo_SD9_DataSheet.pdf","page":2,"quote":"8 x XLR Mic/Line Inputs; 8 x XLR Line Outputs; 2 x XLR AES/EBU Inputs (4 x channels); 2 x XLR AES/EBU Outputs (4 x channels); ... 1 x MADI BNC I/O; 2 x MADI RJ45 Ethercon I/O (for D-Rack)"}},"_notes":["dims order = W x D x H. Line-drawing shows 258 mm height vs PHYSICAL spec 262 mm; used PHYSICAL spec (262).","mixBuses=48 is the flexible 'Aux/Sub-Group' pool; there is ALSO 1 LR/LCR Master buss + 2 Solo busses (not counted in the 48).","auxBuses and groups are null-with-source-null because DiGiCo does NOT publish separate aux-only or group-only counts: aux and sub-group both draw from the single 48-buss pool already recorded in mixBuses.","dca=12 are DiGiCo 'Control Groups (CGs)', usable VCA-style or mute-group-style.","micPreamps/physicalInputs = 8 ONBOARD; full 96-channel input capacity is reached via D-Rack over MADI / Optocore expansion. maxStageboxes not given as a number (2x MADI RJ45 for D-Rack).","16x 32-band GEQs and 12 stereo internal FX also on board (not in schema)."]}$eq$::jsonb)
