insert into equip_product (id, brand, model, category, commercial_status, primary_source_doc, data)
values ('yamaha-cl5', 'Yamaha', 'CL5', 'console', 'current', 'yamaha-cl5-referencemanual-en', $eq${"id":"yamaha-cl5","brand":"Yamaha","model":"CL5","category":"console","physicalInputs":{"value":8,"unit_orig":"OMNI IN (analog)","reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":18,"quote":"CH65-72 ... OMNI1-8"}},"micPreamps":{"value":null,"unit_orig":null,"reliability":"official","source":null},"processingChannels":{"value":72,"unit_orig":"mono input channels","reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":41,"quote":"CH 1-48, CH 49-72/ST IN (CL5)"}},"mixBuses":{"value":24,"unit_orig":"MIX buses","reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":7,"quote":"MIX1-16 tab ... displays MIX buses 1-16.  MIX17-24/MATRIX tab ... displays MIX buses 17-24 and MATRIX buses 1-8."}},"auxBuses":{"value":null,"unit_orig":null,"reliability":"official","source":null},"matrices":{"value":8,"unit_orig":"MATRIX buses","reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":7,"quote":"MIX buses 17-24 and MATRIX buses 1-8"}},"groups":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dca":{"value":16,"unit_orig":"DCA groups","reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":71,"quote":"CL series consoles feature sixteen DCA groups that enable you to control the level of multiple ... channels"}},"directOut":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":26,"quote":"DIRECT OUT PATCH button"}},"insert":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":41,"quote":"Switches the insert on or off. The currently-specified insert point setting appears above"}},"sampleRate_khz":{"value":null,"unit_orig":null,"reliability":"official","source":null},"expansionProtocols":{"value":"Dante (primary audio network); 3x mini-YGDAI (MY) card slots","unit_orig":null,"reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":2,"quote":"CL console internal patching and Dante audio network patching"}},"maxStageboxes":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dims":{"value":"1053 × 299 × 667 mm (W×H×D)","unit_orig":"mm","value_norm":null,"unit_norm":"mm","reliability":"official","source":{"doc":"Yamaha_CL5_OwnerManual_EN.pdf","page":56,"quote":"CL5: 1053mm x 299mm x 667mm, 36kg"},"extractedAt":"2026-07-16"},"weight_kg":{"value":36,"unit_orig":"kg","value_norm":36,"unit_norm":"kg","reliability":"official","source":{"doc":"Yamaha_CL5_OwnerManual_EN.pdf","page":56,"quote":"CL5: 1053mm x 299mm x 667mm, 36kg"},"extractedAt":"2026-07-16"},"powerConsumption_W":{"value":null,"unit_orig":null,"reliability":"official","source":null},"connectors":{"value":"8x OMNI IN + 8x OMNI OUT (onboard analog); Dante primary network; 3x mini-YGDAI (MY) card slots; USB. (Main stage I/O via Rio racks over Dante.)","unit_orig":null,"reliability":"official","source":{"doc":"Yamaha_CL5_ReferenceManual_EN.pdf","page":18,"quote":"CH65-72 ... OMNI1-8 ... OMNI OUT 1 - OMNI OUT 8"}},"_notes":["Source PDF is the CL5/CL3/CL1 Reference (software) Manual: it defines the MIXING ARCHITECTURE cleanly but has NO physical/electrical spec table -> dims, weight, power consumption and native sample rate are null (those live in the CL5 Owner's Manual/datasheet, not provided).","processingChannels=72 mono + 8 stereo 'ST IN' channels (ST IN 1-8 confirmed on PDF p148). Total 80 input channels.","mixBuses=24 (MIX 1-24). On Yamaha these MIX buses are individually switchable VARI (aux) or FIXED (group), so no separate aux-only or group-only count exists -> auxBuses/groups null. STEREO (L/R) + MONO (C) master buses are separate.","physicalInputs=8 OMNI IN onboard; micPreamps null because this manual does not state an onboard mic-preamp count/type (head amps are primarily on Rio I/O racks over Dante).","sampleRate_khz null: the manual only shows MADI-card input-rate detection (44.1/48 kHz), not a stated console native rate. maxStageboxes not specified (Dante Rio racks).","MY card slot count (3) inferred from the I/O patch showing three MY slots; the manual gives no explicit '3 slots' sentence."]}$eq$::jsonb)
