insert into equip_product (id, brand, model, category, commercial_status, primary_source_doc, data)
values ('avid-s6l', 'Avid', 'VENUE | S6L (E6LX-256 engine)', 'console', 'current', 'avid-venue-s6l-productspecs', $eq${"id":"avid-s6l","brand":"Avid","model":"VENUE | S6L (E6LX-256 engine)","category":"console","physicalInputs":{"value":8,"unit_orig":"XLR mic/line (surface)","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":2,"quote":"Analog inputs  8 XLR mic/line inputs with 48V and signal present LEDs"}},"micPreamps":{"value":8,"unit_orig":"preamps (surface)","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":2,"quote":"Analog inputs  8 XLR mic/line inputs with 48V and signal present LEDs"}},"processingChannels":{"value":256,"unit_orig":"input channels","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":1,"quote":"Up to 256 input processing channels, each with built-in HEAT ... (E6LX-256: Input channels 256)"}},"mixBuses":{"value":192,"unit_orig":"mix buses","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":3,"quote":"Mix buses  192 + L-R, C/Mono (E6LX-256)"}},"auxBuses":{"value":null,"unit_orig":null,"reliability":"official","source":null},"matrices":{"value":"64x64","unit_orig":"in x out","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":3,"quote":"Matrix  64 x 64 (E6LX-256); up to 64 mono stereo-linkable Matrixes"}},"groups":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dca":{"value":48,"unit_orig":"VCAs","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":3,"quote":"VCAs  48"}},"directOut":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":16,"quote":"HEAT ..., compressor/limiter, expander/gate, direct output, polarity reverse, 4 pre-fader and 4 post-fader [inserts]"}},"insert":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":3,"quote":"4 pre-fader + 4 post-fader plug-in inserts, 1 pre-fader + 1 post-fader hardware inserts"}},"sampleRate_khz":{"value":96,"unit_orig":"kHz","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":3,"quote":"Sample rates  96 kHz"}},"expansionProtocols":{"value":"AVB (4 ports, etherCON copper or SFP fiber); MADI (stage-box digital splits/outs); AES/EBU; optional cards for MADI, Milan and Waves SoundGrid","unit_orig":null,"reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":1,"quote":"Optional cards for additional MADI, Milan, and Waves SoundGrid"}},"maxStageboxes":{"value":6,"unit_orig":"stage boxes","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":16,"quote":"up to six remote stage boxes containing analog and digital I/O"}},"dims":{"value":"1304 × 787 × 91–388 mm (W×D×Hfront–rear, superficie S6L-24D)","unit_orig":"mm","value_norm":null,"unit_norm":"mm","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ArchitecturalSpecs.pdf","page":2,"quote":"91 mm (H front), 388 mm (H rear), 1304 mm (W), and 787 mm (D)"},"extractedAt":"2026-07-16","note":"superficie S6L-24D; gamma versioni 989–1934 mm W, 38–108 kg"},"weight_kg":{"value":70,"unit_orig":"kg","value_norm":70,"unit_norm":"kg","reliability":"official","source":{"doc":"Avid_VENUE_S6L_ArchitecturalSpecs.pdf","page":2,"quote":"The weight shall be 70 kg/155 lbs"},"extractedAt":"2026-07-16","note":"superficie S6L-24D"},"powerConsumption_W":{"value":null,"unit_orig":null,"reliability":"official","source":null},"connectors":{"value":"Surface: 8x XLR mic/line in; 8x XLR out; 4x AES/EBU stereo pairs in (8 ch); 4x AES/EBU stereo pairs out (8 ch); 2x 1/4\" TRS headphone; 4x AVB (etherCON/SFP); DVI-D; 4x USB 2.0; GPIO 8in/8out; 2x footswitch; LTC in; MIDI I/O","unit_orig":null,"reliability":"official","source":{"doc":"Avid_VENUE_S6L_ProductSpecs.pdf","page":2,"quote":"8 XLR mic/line inputs; 8 XLR outputs; 4 pairs of XLR stereo AES/EBU (8 channels total) [in and out]; 2 independent 1/4-inch TRS stereo headphone jacks; ... AVB ... 4, each providing etherCON (copper) or SFP"}},"_notes":["S6L is a MODULAR SYSTEM = control surface (S6L-48D/-32D/-24D/-24C/-16C) + engine (E6LX-256/E6L-192/-144/-112) + stage boxes (Stage 64/48/32/16). This record = FLAGSHIP E6LX-256 engine (headline 'up to' figures).","Engine-dependent: mix buses 192/96/64/48, matrix 64x64/24x24/16x16/16x16, input channels 256/192/144/112 for E6LX-256/E6L-192/-144/-112 respectively; VCAs 48 and 2 stereo monitor buses on all.","auxBuses/groups null: the 192 mix buses are user-configurable roles; Avid does not publish separate aux-only/group-only counts.","physicalInputs/micPreamps = 8 on the control surface ONLY; real input capacity (up to 256) comes from Stage boxes (Stage 64 = 64 mic/line each), up to six stage boxes.","dims/weight/powerConsumption null: this Product Specs doc gives surface dimensions ONLY as line drawings (e.g. S6L-48D ~1934 mm wide) with no clean W/D/H table, no weight, and power stated only as voltage range (100-240V), no wattage."]}$eq$::jsonb)
