insert into equip_product (id, brand, model, category, commercial_status, primary_source_doc, data)
values ('ah-sq5', 'Allen & Heath', 'SQ-5', 'console', 'current', 'allenheath-sq-referenceguide', $eq${"id":"ah-sq5","brand":"Allen & Heath","model":"SQ-5","category":"console","physicalInputs":{"value":16,"unit_orig":"XLR mic/line","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":7,"quote":"SQ-5  16+master [faders]  16+talkback [preamps]  12 [XLR outputs]"}},"micPreamps":{"value":16,"unit_orig":"preamps","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":7,"quote":"SQ-5 ... Preamps 16+talkback"}},"processingChannels":{"value":48,"unit_orig":"input channels","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":10,"quote":"Input channels – 48 input channels with processing. These can be sourced from local, [SLink, I/O port, USB, etc.]"}},"mixBuses":{"value":12,"unit_orig":"stereo mix channels","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":10,"quote":"Mix channels –12 stereo mix channels with processing that can be used as either [Aux or Group]"}},"auxBuses":{"value":null,"unit_orig":null,"reliability":"official","source":null},"matrices":{"value":3,"unit_orig":"stereo matrix buses","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":10,"quote":"Matrix – 3 stereo matrix buses that can be made up of a combination of other buses."}},"groups":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dca":{"value":8,"unit_orig":"DCA channels","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":10,"quote":"DCA – 8 ‘Digitally Controlled Amplifier’ channels for adjusting the level and mutes of [multiple channels]"}},"directOut":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":39,"quote":"8.1 Direct Out"}},"insert":{"value":true,"unit_orig":null,"reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":31,"quote":"Inserts can also be used with the internal FX engines."}},"sampleRate_khz":{"value":96,"unit_orig":"kHz","reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":7,"quote":"built on an Allen & Heath XCVI core, the SQ series of digital mixers feature 96kHz variable bit-depth"}},"expansionProtocols":{"value":"SLink (mode-switchable dSNAKE/ME 48kHz, DX 96kHz, gigaACE/GX 96kHz); I/O Port option-card slot (e.g. Dante/Waves/MADI)","unit_orig":null,"reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":17,"quote":"SLink ... Remote Audio Units. Mode switchable between dSnake/ME, DX and gigaACE/GX"}},"maxStageboxes":{"value":null,"unit_orig":null,"reliability":"official","source":null},"dims":{"value":"501.9 × 198 × 514.9 mm (W×H×D)","unit_orig":"mm","value_norm":null,"unit_norm":"mm","reliability":"official","source":{"doc":"AllenHeath_SQ-5_TechnicalDatasheet.pdf","page":2,"quote":"501.9mm/19.8\" ... 198mm/7.8\" ... 514.9mm/20.3\""},"extractedAt":"2026-07-16"},"weight_kg":{"value":null,"unit_orig":null,"reliability":"official","source":null},"powerConsumption_W":{"value":null,"unit_orig":null,"reliability":"official","source":null},"connectors":{"value":"SQ-5: 16x XLR mic/line in; 12x XLR out; 2x stereo TRS line in (ST1/ST2); SLink (etherCON); I/O Port (option card); Network (RJ45); SQ-Drive USB. (Some counts are SQ-5-specific; SQ-6=24 pre/14 out, SQ-7=32 pre/16 out.)","unit_orig":null,"reliability":"official","source":{"doc":"AllenHeath_SQ_ReferenceGuide.pdf","page":16,"quote":"ST1, ST2 (1/4” TRS jack) – Labelled as stereo pairs, these can also be used as mono"}},"_notes":["Source PDF is the SQ-5/SQ-6/SQ-7 Reference Guide (shared XCVI processing engine). Processing figures (48 in, 12 stereo mix, 3 stereo matrix, 8 DCA, 8 stereo FX returns, 4 FX sends) are identical across all three models.","This record = SQ-5. SQ-5-specific hardware: 16 preamps (16 mic/line XLR) + 2 stereo TRS line inputs (ST1/ST2), 12 XLR outputs, 16 faders + master.","mixBuses=12 STEREO mixes, each configurable as Aux or Group -> auxBuses/groups null (no separate fixed count). matrices=3 are STEREO matrix buses.","Physical dims, weight and power consumption are NOT in this Reference Guide (they live in the SQ hardware/Getting Started guide, not provided) -> null.","maxStageboxes null: SLink drives Remote Audio Units (e.g. dSNAKE 40 in / 20 out; DX/gigaACE 32/32 or more) but no fixed max-boxes number is stated."]}$eq$::jsonb)
