values ('meyer-leopard', 'Meyer Sound', 'LEOPARD', 'line_array', 'current', 'meyersound-leopard-datasheet', $eq${"id":"meyer-leopard","brand":{"value":"Meyer Sound","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":1,"quote":"LEOPARD Compact Linear Line Array Loudspeaker"}},"model":{"value":"LEOPARD","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":1,"quote":"LEOPARD Compact Linear Line Array Loudspeaker"}},"category":{"value":"line_array","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":1,"quote":"LEOPARD Compact Linear Line Array Loudspeaker"}},"active":{"value":true,"unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":1,"quote":"the same advantages of self-powered design, linear response, and precise directional control; A class D amplifier ... A single, field-replaceable module contains the on-board amplifier and control circuitry."}},"transducers":{"value":"2×9″ LF cone + 1×3″ HF compression","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Low Frequency: Two 9-inch long-excursion cone drivers; 2 Ω nominal impedance. High Frequency: One 3-inch diaphragm compression driver coupled to a constant-directivity horn through a patented REM manifold; 4 Ω nominal impedance"}},"freqResp_lo_hz":{"value":55,"unit_orig":"Hz","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Operating Frequency Range: 55 Hz – 18 kHz"}},"freqResp_hi_hz":{"value":18000,"unit_orig":"Hz","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Operating Frequency Range: 55 Hz – 18 kHz"}},"maxSPL_db":{"value":142,"unit_orig":"dB","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Maximum SPL: 142 dB (peak measured in free-field at 4 m referred to 1 m using noise)"}},"dispersion":{"value":"110° (H) × varies (V)","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Horizontal Coverage: 110°. Vertical Coverage: Varies, depending on array length and configuration"}},"power_handling_W":{"value":3900,"unit_orig":"W","reliability":"official","note":"AUDIO power = amplifier total output (peak), self-powered unit; not electrical consumption","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"AMPLIFIERS Type: 3-channel, open-loop, class D. Total Output Power: 3900 W peak"}},"powerConsumption_W":{"value":1.5,"unit_orig":"A","reliability":"official","note":"ELECTRICAL draw given only as current (A), not W. Value = max long-term continuous current at 230 V AC; datasheet also lists 3.0 A @115V, 3.4 A @100V","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"CURRENT DRAW Max Long-Term Continuous Current (>10 sec): 3.0 A rms (115 V AC); 1.5 A rms (230 V AC); 3.4 A rms (100 V AC)"}},"voltage_range":{"value":"100–240 V AC, 50–60 Hz","unit_orig":"V","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Automatic Voltage Selection: 90–265 V AC. Safety Rated Voltage Range: 100–240 V AC, 50–60 Hz"}},"dims_w_mm":{"value":684,"unit_orig":"mm","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":4,"quote":"Dimensions: W: 26.93 in (684 mm) x H: 11.11 in (282 mm) x D: 21.66 in (550 mm)"}},"dims_d_mm":{"value":550,"unit_orig":"mm","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":4,"quote":"Dimensions: W: 26.93 in (684 mm) x H: 11.11 in (282 mm) x D: 21.66 in (550 mm)"}},"dims_h_mm":{"value":282,"unit_orig":"mm","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":4,"quote":"Dimensions: W: 26.93 in (684 mm) x H: 11.11 in (282 mm) x D: 21.66 in (550 mm)"}},"weight_kg":{"value":34,"unit_orig":"kg","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":4,"quote":"Weight: 75 lb (34.0 kg)"}},"rigging":{"value":"QuickFly rigging; end frames with captive GuideALinks, quick-release pins, 0.5°–15° splay angles; detachable side/rear handles","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":4,"quote":"Rigging: End frames with captive GuideALinks secured with 0.3125 in x 0.63 in quick-release pins that allow 0.5° to 15° splay angles; detachable side and rear handles"}},"connectors":{"value":"Audio IN: XLR 5-pin female + male loop out (balanced audio + RMS), or XLR 3-pin (audio only). AC: powerCON 20 in + loop out","unit_orig":"","reliability":"official","source":{"doc":"MeyerSound_LEOPARD_Datasheet.pdf","page":3,"quote":"Connectors: XLR 5-pin female input with male loop output; XLR 3-pin female connectors available to accommodate only balanced audio. AC POWER Connector: powerCON 20 input with loop output"}}}$eq$::jsonb)
