values ('db-sl-sub', 'd&b audiotechnik', 'SL-SUB (flown) / SL-GSUB (ground-stack)', 'subwoofer', 'current', 'dbaudio-sl-sub-datasheet', $eq${"id":"db-sl-sub","brand":{"value":"d&b audiotechnik","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"The loudspeaker shall be the SL-SUB and SL-GSUB by d&b audiotechnik GmbH & Co. KG."}},"model":{"value":"SL-SUB (flown) / SL-GSUB (ground-stack)","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"The SL-SUB and SL-GSUB are cardioid subwoofers to compliment the GSL and KSL Systems."}},"category":{"value":"subwoofer","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"The SL-SUB and SL-GSUB are cardioid subwoofers ... actively driven 2-way bass-reflex designs"}},"active":{"value":false,"unit_orig":"","reliability":"official","note":"'actively driven 2-way' = active crossover in the amp, NOT self-powered. Cabinet is passive; requires external d&b D80 amplifier (2 channels/cabinet).","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"The d&b D80 amplifier is required to drive the SL-SUB and SL-GSUB. These large format subwoofers are driven in 2-Way Active mode and require two amplifier channels per cabinet."}},"transducers":{"value":"3×21″ neodymium (2 front + 1 rear, cardioid)","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"housing three long excursion 21\" neodymium drivers. Two drivers face to the front while one radiates to the rear. Components: 3 x 21\" driver"}},"freqResp_lo_hz":{"value":33,"unit_orig":"Hz","reliability":"official","note":"-5 dB standard mode; INFRA mode = 30 Hz","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"Frequency response (–5 dB standard): 33 Hz - 84 Hz. Frequency response (–5 dB INFRA mode): 30 Hz - 65 Hz"}},"freqResp_hi_hz":{"value":84,"unit_orig":"Hz","reliability":"official","note":"-5 dB standard mode; INFRA mode = 65 Hz","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"Frequency response (–5 dB standard): 33 Hz - 84 Hz. Frequency response (–5 dB INFRA mode): 30 Hz - 65 Hz"}},"maxSPL_db":{"value":144,"unit_orig":"dB","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"Max. sound pressure (1 m, free field) with D80: 144 dB (SPLmax: Broadband signal IEC 60268)"}},"dispersion":{"value":"Cardioid (no rated H×V for subwoofer)","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"The cardioid dispersion pattern reduces unwanted energy behind the system ... Cardioid output pattern rejects the transmission of energy towards the rear"}},"power_handling_W":{"value":1500,"unit_orig":"W","reliability":"official","note":"AUDIO power handling (passive cabinet), NOT electrical consumption. Value = front RMS + rear RMS = 1000 + 500 W. Peak (10 ms) = 4000 + 2000 = 6000 W.","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"Power handling capacity front (RMS/peak 10 ms): 1000/4000 W. Power handling capacity rear (RMS/peak 10 ms): 500/2000 W"}},"powerConsumption_W":{"value":null,"unit_orig":"W","reliability":"official","note":"Passive cabinet with no onboard amplifier; electrical consumption belongs to the external d&b D80 amp, not stated in this datasheet.","source":null},"voltage_range":{"value":null,"unit_orig":"V","reliability":"official","note":"Passive cabinet, no AC mains input.","source":null},"dims_w_mm":{"value":1300,"unit_orig":"mm","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":2,"quote":"Front view width: 1300 [51.2] (cabinet dimensions in mm [inch])"}},"dims_d_mm":{"value":1100,"unit_orig":"mm","reliability":"official","note":"Side/top view depth; drawing shows 975 [38.4] and 1100 [43.3] — reporting overall 1100 mm.","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":2,"quote":"Side/Top view depth: 975 [38.4] / 1100 [43.3]"}},"dims_h_mm":{"value":585,"unit_orig":"mm","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":2,"quote":"Front view height: 585 [23]"}},"weight_kg":{"value":138,"unit_orig":"kg","reliability":"official","note":"SL-SUB (flown). SL-GSUB (ground-stack) = 132 kg.","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"Weight SL-SUB: 138 kg (304 lb). Weight SL-GSUB: 132 kg (291 lb)"}},"rigging":{"value":"SL-SUB: front & rear rigging strands, up to 14 cabinets flown in a vertical column. SL-GSUB: no rigging (ground-stack only)","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"The SL-SUB rigging hardware allows columns of up to fourteen cabinets to be flown while the SL-GSUB is intended for ground stacked applications only ... The SL-GSUB has no rigging components"}},"connectors":{"value":"1 × NLT4 F (speakON NL4); requires external d&b D80 amp, 2 channels/cabinet","unit_orig":"","reliability":"official","source":{"doc":"dbaudio_SL-SUB_Datasheet.pdf","page":1,"quote":"Connections: 1 x NLT4 F"}}}$eq$::jsonb)
