values ('lacoustics-k2', 'L-Acoustics', 'K2', 'line_array', 'current', 'lacoustics-k2-usermanual', $eq${"id":"lacoustics-k2","brand":{"value":"L-Acoustics","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"K2 owner's manual"}},"model":{"value":"K2","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"K2 specifications"}},"category":{"value":"line_array","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Description: 3-way full-range active WST enclosure, quad-amplified by LA4X / LA8 / LA12X"}},"active":{"value":false,"unit_orig":"","reliability":"official","note":"'active WST' = active crossover; enclosure is passive and quad-amplified by an EXTERNAL L-Acoustics controller (LA4X/LA8/LA12X). Not self-powered.","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Description: 3-way full-range active WST enclosure, quad-amplified by LA4X / LA8 / LA12X. The K2 is driven and quad-amplified by the LA12X, LA8 or LA4X controller"}},"transducers":{"value":"2×12″ LF cone + 4×6.5″ MF cone + 2×3″ HF compression","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Transducers: LF: 2 × 12\" cone drivers; MF: 4 × 6.5\" cone drivers; HF: 2 × 3\" diaphragm compression drivers"}},"freqResp_lo_hz":{"value":35,"unit_orig":"Hz","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Usable bandwidth (-10 dB): 35 Hz - 20 kHz ([K2 70])"}},"freqResp_hi_hz":{"value":20000,"unit_orig":"Hz","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Usable bandwidth (-10 dB): 35 Hz - 20 kHz ([K2 70])"}},"maxSPL_db":{"value":147,"unit_orig":"dB","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Maximum SPL: 147 dB ([K2 70]) — Peak level measured at 1 m under free field conditions using pink noise with crest factor 4"}},"dispersion":{"value":"110°/70° symmetric or 90° asymmetric (H) × varies (V)","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Nominal directivity (-6 dB): horizontal: 110°/70° symmetric or 90° asymmetric (35°/55° or 55°/35°); vertical: dependent upon the number of elements and the line source curvature"}},"power_handling_W":{"value":null,"unit_orig":"W","reliability":"official","note":"Not stated in the K2 spec table (only nominal impedance given: LF 2×8 Ω, MF 8 Ω, HF 16 Ω). Power is defined by the external LA amplified controller.","source":null},"powerConsumption_W":{"value":null,"unit_orig":"W","reliability":"official","note":"Passive enclosure with no onboard amplifier; electrical consumption belongs to the external LA4X/LA8/LA12X controller, not stated here.","source":null},"voltage_range":{"value":null,"unit_orig":"V","reliability":"official","note":"Passive enclosure, no AC mains input.","source":null},"dims_w_mm":{"value":1338,"unit_orig":"mm","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":162,"quote":"K2 dimensions: 1338 mm / 52.7 in (width)"}},"dims_d_mm":{"value":400,"unit_orig":"mm","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":162,"quote":"K2 dimensions: 400 mm / 15.8 in (depth)"}},"dims_h_mm":{"value":354,"unit_orig":"mm","reliability":"official","note":"Front height 354 mm; trapezoidal cabinet also shows 286 mm / 11.3 in (rear).","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":162,"quote":"K2 dimensions: 354 mm / 13.9 in and 286 mm / 11.3 in (height, trapezoidal)"}},"weight_kg":{"value":56,"unit_orig":"kg","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Weight (net): 56 kg / 123.2 lb"}},"rigging":{"value":"4-point captive rigging system; inter-enclosure angles 0.25°, 1°, 2°, 3°, 4°, 5°, 7.5°, 10°","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Rigging and handling: 4-point captive rigging system; inter-enclosure angles: 0.25°, 1°, 2°, 3°, 4°, 5°, 7.5° or 10°"}},"connectors":{"value":"IN: 1 × 8-point PA-COM; LINK: 1 × 8-point PA-COM","unit_orig":"","reliability":"official","source":{"doc":"LAcoustics_K2_UserManual.pdf","page":161,"quote":"Connectors: IN: 1 × 8-point PA-COM; LINK: 1 × 8-point PA-COM"}}}$eq$::jsonb)
