values ('jbl-vtx-a12', 'JBL Professional', 'VTX A12', 'line_array', 'current', 'jbl-vtx-a12-spec', $eq${"id":"jbl-vtx-a12","brand":{"value":"JBL Professional","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":1,"quote":"VTX SERIES | A12 ... JBL Professional is the world's leading manufacturer of loudspeaker systems (Harman International Industries)"}},"model":{"value":"VTX A12","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":1,"quote":"VTX SERIES | A12 — Dual 12-inch Line Array Loudspeaker | 90-Degree Dispersion"}},"category":{"value":"line_array","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":1,"quote":"Dual 12-inch Line Array Loudspeaker | 90-Degree Dispersion"}},"active":{"value":false,"unit_orig":"","reliability":"official","note":"Passive: requires external Crown I-Tech amplifiers, 4 amp channels (LF|LF|MF|HF).","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"System Amplification: Crown I-Tech 9000HD / 12000HD / 4x3500HD. Required Amplifier Channels: (4) channels (LF|LF|MF|HF)"}},"transducers":{"value":"2×12″ LF + 4×5.5″ MF + 3×2″ HF compression (9 transducers, 3-way)","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Low Frequency: (2) JBL 2264H, 12 in. Mid Frequency: (4) JBL 2165H, 5.5 in. High Frequency: (3) JBL 2423K, 2 in annular diaphragm compression drivers"}},"freqResp_lo_hz":{"value":46,"unit_orig":"Hz","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Frequency Range (-10 dB): 46 Hz - 19 kHz (Preset: VTX A12)"}},"freqResp_hi_hz":{"value":19000,"unit_orig":"Hz","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Frequency Range (-10 dB): 46 Hz - 19 kHz (Preset: VTX A12)"}},"maxSPL_db":{"value":146,"unit_orig":"dB","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Maximum Peak Output: 146 dB (Preset: VTX A12) — Peak, unweighted SPL at 1 m, broadband pink noise, 12 dB crest factor"}},"dispersion":{"value":"90° (H, nominal 250 Hz–18 kHz) × varies (V)","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Coverage Pattern (-6 dB) Horizontal: 90 degrees nominal (250 Hz - 18 kHz); Vertical: Varies with array size and configuration"}},"power_handling_W":{"value":2150,"unit_orig":"W","reliability":"official","note":"AUDIO power handling (passive cabinet), NOT electrical consumption. Value = continuous input power sum: LF 2×800 + MF 400 + HF 150 (IEC, 100 h).","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"System Input Power Rating: LF: 2x 800W Continuous (IEC/100 hour); MF: 400W Continuous; HF: 150W Continuous"}},"powerConsumption_W":{"value":null,"unit_orig":"W","reliability":"official","note":"Passive cabinet with no onboard amplifier; electrical consumption belongs to the external Crown I-Tech amps, not stated in this datasheet.","source":null},"voltage_range":{"value":null,"unit_orig":"V","reliability":"official","note":"Passive cabinet, no AC mains input.","source":null},"dims_w_mm":{"value":1118,"unit_orig":"mm","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Dimensions (H x W x D): 330 mm x 1118 mm x 495 mm"}},"dims_d_mm":{"value":495,"unit_orig":"mm","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Dimensions (H x W x D): 330 mm x 1118 mm x 495 mm"}},"dims_h_mm":{"value":330,"unit_orig":"mm","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Dimensions (H x W x D): 330 mm x 1118 mm x 495 mm"}},"weight_kg":{"value":60.8,"unit_orig":"kg","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Net Weight: 60.8 kg (134 lbs)"}},"rigging":{"value":"High-grade steel, captive suspension plates, quick-release pins, auto-locking angle mechanism; inter-enclosure angles 0.25–10°","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Suspension: High-grade steel with anti-corrosion coating, captive suspension plates, quick release pins, auto-locking mechanism for setting angles. Inter-enclosure Angle (deg): 0.25, 0.5, 1, 1.5, 2, 2.5, 3, 4, 6, 8, 10"}},"connectors":{"value":"2 × Neutrik speakON NL-8 (Pins 1±/2± LF, 3± MF, 4± HF)","unit_orig":"","reliability":"official","source":{"doc":"JBL_VTX-A12_Spec.pdf","page":2,"quote":"Connectors Type: (2) Neutrik speakON NL-8. Pin Assignments: Pins 1 ± (LF), Pins 2 ± (LF), Pins 3 ± (MF), Pins 4 ± (HF)"}}}$eq$::jsonb)
